// components/TopicList.jsx — Glass-grouped vertical topic list
import React from "react";
import { Link } from "react-router-dom";
import { CATEGORIES } from "../data/topicsData";
import { getCompletedTopics } from "../utils/progress";

const CATEGORY_ICONS = {
  "Arithmetic":   "∑",
  "Work & Speed": "⚡",
  "Algebra":      "χ",
  "Geometry":     "△",
  "Data & Logic": "◈",
};

export default function TopicList({ topics }) {
  const completed = getCompletedTopics();

  if (topics.length === 0) {
    return (
      <div className="glass py-12 text-center animate-fade-in">
        <p className="text-slate-500 text-sm">No topics match your search.</p>
      </div>
    );
  }

  const grouped = CATEGORIES.reduce((acc, cat) => {
    const items = topics.filter((t) => t.category === cat);
    if (items.length > 0) acc[cat] = items;
    return acc;
  }, {});

  return (
    <div className="space-y-5">
      {Object.entries(grouped).map(([category, items], gi) => (
        <div
          key={category}
          className="glass animate-fade-up overflow-hidden"
          style={{ animationDelay: `${gi * 0.07}s` }}
        >
          {/* Category header */}
          <div
            className="flex items-center gap-3 px-5 py-3"
            style={{ borderBottom: "1px solid rgba(255,255,255,0.06)" }}
          >
            <span
              className="w-7 h-7 flex items-center justify-center rounded-lg text-xs font-mono font-bold"
              style={{
                background: "rgba(99,102,241,0.15)",
                color: "#818cf8",
                border: "1px solid rgba(99,102,241,0.20)",
              }}
            >
              {CATEGORY_ICONS[category] || "○"}
            </span>
            <span className="section-label">{category}</span>
            <span
              className="ml-auto text-xs font-mono"
              style={{ color: "#475569" }}
            >
              {items.length}
            </span>
          </div>

          {/* Topic rows */}
          <ul className="list-none m-0 p-0">
            {items.map((topic, idx) => {
              const isDone = completed.includes(topic.slug);
              return (
                <li key={topic.slug} className="topic-row last:border-0">
                  <Link
                    to={`/topic/${topic.slug}`}
                    className="flex items-center justify-between px-5 py-3 group no-underline"
                  >
                    <div className="flex items-center gap-3">
                      <span
                        className="text-xs font-mono w-5 text-right shrink-0"
                        style={{ color: "#334155" }}
                      >
                        {String(idx + 1).padStart(2, "0")}
                      </span>
                      <span className="text-sm text-slate-300 group-hover:text-white transition-colors font-medium">
                        {topic.name}
                      </span>
                    </div>
                    <div className="flex items-center gap-2.5">
                      {isDone && (
                        <span className="badge badge-green">✓ done</span>
                      )}
                      <span
                        className="text-slate-600 group-hover:text-primary transition-all duration-200 group-hover:translate-x-0.5"
                        style={{ display: "inline-block" }}
                      >
                        →
                      </span>
                    </div>
                  </Link>
                </li>
              );
            })}
          </ul>
        </div>
      ))}
    </div>
  );
}
